// Gelen veriyi al - farklı yapıları kontrol et
let videos;
const input = $input.all();

// Eğer veri direkt array olarak geldiyse
if (Array.isArray(input) && input.length > 0) {
  if (input[0].json && !Array.isArray(input[0].json)) {
    videos = input.map(item => item.json);
  } 
  else if (Array.isArray(input[0].json)) {
    videos = input[0].json;
  }
  else if (input[0].json && input[0].json.body) {
    videos = input[0].json.body;
  }
  else {
    videos = input;
  }
}

// En çok izlenene göre sırala
videos.sort((a, b) => (b.viewCount || 0) - (a.viewCount || 0));

// En iyi 5 videoyu döndür
return videos.slice(0, 5).map(video => ({ json: video }));

