const output = $json.output;
const allItems = [];

// Long form'ları ekle
if (output.long_form) {
  output.long_form.forEach((item) => {
    allItems.push({
      json: {
        tarih: item.publish_date,
        baslik: item.title,
        aciklama: item.description,
        format: 'long',
        'ana-tema': item.prompt,
        'sahne-prompt': '',
        durum: 'planlandı'
      }
    });
  });
}

// Shorts'ları ekle
if (output.shorts) {
  output.shorts.forEach((item) => {
    allItems.push({
      json: {
        tarih: item.publish_date,
        baslik: item.title,
        aciklama: item.description,
        format: 'short',
        'ana-tema': item.prompt,
        'sahne-prompt': '',
        durum: 'planlandı'
      }
    });
  });
}

return allItems;

const aylar = ['Ocak', 'Şubat', 'Mart', 'Nisan', 'Mayıs', 'Haziran', 
               'Temmuz', 'Ağustos', 'Eylül', 'Ekim', 'Kasım', 'Aralık'];

// TSİ için UTC+3
const now = new Date();
const tpiTime = new Date(now.getTime() + (3 * 60 * 60 * 1000));

const gun = tpiTime.getUTCDate();
const ay = aylar[tpiTime.getUTCMonth()];
const yil = tpiTime.getUTCFullYear();

const bugunTarih = `${gun} ${ay} ${yil}`;

return [{ json: { bugunTarih } }];
